// Parses an incoming Slack /engage slash command (form-encoded → $json.body).
// Extracts the LinkedIn post URL from `text` (handles Slack's <url> formatting),
// plus channel_id / user_id / response_url for downstream notification.
const body = $input.first().json.body || {};
const rawText = String(body.text || '').trim();

// Slack often wraps URLs in angle brackets: <https://linkedin.com/posts/...> or <https://...|display>
const urlMatch = rawText.match(/<(https?:\/\/[^|>]+)/);
const postUrl = urlMatch ? urlMatch[1] : rawText;

if (!postUrl.startsWith('http')) {
  throw new Error(`No URL found in slash command text: "${rawText}"`);
}

return [{
  json: {
    postUrl,
    channelId: String(body.channel_id || ''),
    userId: String(body.user_id || ''),
    responseUrl: String(body.response_url || ''),
  }
}];
